import Link from "next/link";
import { SignInButton, SignedIn, SignedOut, UserButton } from "@clerk/nextjs";
import { Code2, Users, Trophy, Brain, Zap, Target } from "lucide-react";

export default function LandingPage() {
  const features = [
    {
      icon: Users,
      title: "Race with Friends",
      description: "Join real-time coding races and compete with friends in live sessions.",
    },
    {
      icon: Brain,
      title: "AI Interview Practice",
      description: "Practice coding interviews with AI-powered feedback and guidance.",
    },
    {
      icon: Trophy,
      title: "Leaderboard",
      description: "Climb the ranks and compete for the top spot on the leaderboard.",
    },
    {
      icon: Code2,
      title: "Problem Solving",
      description: "Solve challenging problems and improve your coding skills.",
    },
    {
      icon: Zap,
      title: "Real-time Collaboration",
      description: "Work together in real-time coding rooms with live updates.",
    },
    {
      icon: Target,
      title: "Track Progress",
      description: "Monitor your performance and track your coding journey.",
    },
  ];

  return (
    <div className="min-h-screen flex flex-col bg-gradient-to-br from-slate-900 via-blue-900 to-purple-900">
      {/* Header with glass effect */}
      <header className="sticky top-0 z-50 glass border-b border-white/10">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <Link href="/" className="font-bold text-xl gradient-text">
            Realtime Coding Arena
          </Link>
          <div className="flex items-center gap-4">
            <SignedOut>
              <SignInButton mode="modal">
                <button className="text-sm font-medium hover:text-blue-400 transition-colors">
                  Sign in
                </button>
              </SignInButton>
              <Link
                href="/sign-up"
                className="rounded-md gradient-primary px-4 py-2 text-sm text-white font-medium hover:opacity-90 transition-opacity shadow-lg shadow-blue-500/50"
              >
                Get started
              </Link>
            </SignedOut>
            <SignedIn>
              <Link
                href="/dashboard"
                className="text-sm font-medium hover:text-blue-400 transition-colors"
              >
                Dashboard
              </Link>
              <UserButton afterSignOutUrl="/" />
            </SignedIn>
          </div>
        </div>
      </header>

      {/* Hero Section */}
      <main className="flex-1">
        <section className="relative overflow-hidden py-20 px-4 sm:py-32">
          {/* Gradient background overlay */}
          <div className="absolute inset-0 bg-gradient-to-br from-blue-600/20 via-purple-600/20 to-pink-600/20"></div>
          
          {/* Animated gradient orbs */}
          <div className="absolute top-0 left-1/4 w-96 h-96 bg-blue-500/30 rounded-full blur-3xl animate-pulse"></div>
          <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-purple-500/30 rounded-full blur-3xl animate-pulse delay-1000"></div>
          
          <div className="relative container mx-auto text-center max-w-4xl">
            <h1 className="text-5xl sm:text-6xl md:text-7xl font-bold tracking-tight mb-6">
              <span className="gradient-text">
                Realtime Coding Arena
              </span>
              <br />
              <span className="text-white">
                + AI Interview Platform
              </span>
            </h1>
            <p className="text-lg sm:text-xl text-gray-300 mb-10 max-w-2xl mx-auto">
              Race with friends, practice with AI, and level up your coding
              skills. Join rooms, solve problems, and climb the leaderboard.
            </p>
            <div className="flex flex-col sm:flex-row gap-4 justify-center items-center">
              <SignedIn>
                <Link
                  href="/dashboard"
                  className="inline-flex rounded-lg gradient-primary px-8 py-4 text-white font-semibold hover:opacity-90 transition-all duration-300 shadow-xl shadow-purple-500/50 hover:shadow-2xl hover:shadow-purple-500/70 transform hover:scale-105"
                >
                  Go to Dashboard
                </Link>
              </SignedIn>
              <SignedOut>
                <Link
                  href="/sign-up"
                  className="inline-flex rounded-lg gradient-primary px-8 py-4 text-white font-semibold hover:opacity-90 transition-all duration-300 shadow-xl shadow-purple-500/50 hover:shadow-2xl hover:shadow-purple-500/70 transform hover:scale-105"
                >
                  Get started
                </Link>
              </SignedOut>
            </div>
          </div>
        </section>

        {/* Features Section */}
        <section className="py-20 px-4 relative">
          <div className="container mx-auto max-w-7xl">
            <div className="text-center mb-16">
              <h2 className="text-4xl sm:text-5xl font-bold mb-4">
                <span className="gradient-text">Powerful Features</span>
              </h2>
              <p className="text-gray-400 text-lg max-w-2xl mx-auto">
                Everything you need to improve your coding skills and compete at the highest level
              </p>
            </div>
            
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {features.map((feature, index) => {
                const Icon = feature.icon;
                return (
                  <div
                    key={index}
                    className="group relative p-6 rounded-xl glass border border-white/10 hover:border-blue-500/50 transition-all duration-300 hover:shadow-xl hover:shadow-purple-500/20 transform hover:-translate-y-1"
                  >
                    {/* Gradient accent */}
                    <div className="absolute inset-0 rounded-xl bg-gradient-to-br from-blue-500/0 via-purple-500/0 to-pink-500/0 group-hover:from-blue-500/10 group-hover:via-purple-500/10 group-hover:to-pink-500/10 transition-all duration-300"></div>
                    
                    <div className="relative">
                      <div className="w-12 h-12 rounded-lg gradient-primary flex items-center justify-center mb-4 shadow-lg shadow-blue-500/50">
                        <Icon className="w-6 h-6 text-white" />
                      </div>
                      <h3 className="text-xl font-semibold mb-2 text-white">
                        {feature.title}
                      </h3>
                      <p className="text-gray-400">
                        {feature.description}
                      </p>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </section>
      </main>
    </div>
  );
}
